/**
 * bda-source-page.js
 *
 * Page-level interactivity for individual source pages at
 * /archive/sources/entries/[source_id]/.
 *
 * These pages are static HTML generated by tools/build_sources.py — ALL
 * rendering, citation generation, metadata, cited-in, related sources,
 * access-level gating, and transcript embedding happens at build time in
 * Python.
 *
 * This script handles only post-render UI behaviors:
 *   - Citation format toggle (swap visible citation when a radio is clicked)
 *   - Copy-to-clipboard for header permalink, rail permalink, and citation
 *   - Multi-asset viewer tab switching (arrow key navigation, Home/End)
 *
 * Loads after partials.js. Requires no data fetch.
 *
 * WCAG 2.2 Level AA:
 *   - Radio group is native HTML, keyboard-accessible by default
 *   - Copy buttons announce success/failure via aria-live status spans
 *   - Tab navigation follows APG tablist pattern (arrow/Home/End)
 */
(function () {
    'use strict';

    // ---------------------------------------------------------------------
    // Copy-to-clipboard helpers
    // ---------------------------------------------------------------------

    function announceCopy(statusEl, message) {
        if (!statusEl) return;
        statusEl.textContent = message;
        // Clear the message after 3 seconds so the live region isn't stale.
        setTimeout(function () {
            if (statusEl.textContent === message) {
                statusEl.textContent = '';
            }
        }, 3000);
    }

    function copyToClipboard(text, statusEl) {
        function ok() { announceCopy(statusEl, 'Copied to clipboard'); }
        function fail() {
            announceCopy(statusEl, 'Could not copy. Press Ctrl+C or Cmd+C to copy manually.');
        }

        if (navigator.clipboard && typeof navigator.clipboard.writeText === 'function') {
            return navigator.clipboard.writeText(text).then(ok, fail);
        }

        // Legacy fallback for older browsers / insecure contexts
        try {
            var ta = document.createElement('textarea');
            ta.value = text;
            ta.setAttribute('readonly', '');
            ta.style.position = 'absolute';
            ta.style.left = '-9999px';
            document.body.appendChild(ta);
            ta.select();
            var success = document.execCommand && document.execCommand('copy');
            document.body.removeChild(ta);
            if (success) { ok(); } else { fail(); }
        } catch (e) {
            fail();
        }
    }

    // ---------------------------------------------------------------------
    // Citation format toggle
    // ---------------------------------------------------------------------

    function initCitationFormatToggle() {
        var citationSection = document.getElementById('bda-source-citation');
        if (!citationSection) return;

        var radios = citationSection.querySelectorAll('input[name="citation-format"]');
        if (radios.length === 0) return;

        // Collect all citation text divs keyed by format
        var citationDivs = {};
        citationSection.querySelectorAll('.bda-citation-text').forEach(function (div) {
            var fmt = div.getAttribute('data-citation-format');
            if (fmt) citationDivs[fmt] = div;
        });

        function showFormat(format) {
            Object.keys(citationDivs).forEach(function (fmt) {
                citationDivs[fmt].hidden = (fmt !== format);
            });
        }

        // Wire each radio
        radios.forEach(function (radio) {
            radio.addEventListener('change', function () {
                if (radio.checked) {
                    showFormat(radio.value);
                }
            });
        });

        // Ensure the initially-checked radio matches what's visible
        var initial = citationSection.querySelector('input[name="citation-format"]:checked');
        if (initial) showFormat(initial.value);
    }

    // ---------------------------------------------------------------------
    // Citation copy button
    // ---------------------------------------------------------------------

    function initCitationCopyButton() {
        var citationSection = document.getElementById('bda-source-citation');
        if (!citationSection) return;

        var copyBtn = citationSection.querySelector('.bda-citation-copy-btn');
        if (!copyBtn) return;

        var statusEl = document.getElementById('bda-citation-copy-status');

        copyBtn.addEventListener('click', function () {
            // Find the currently-visible citation div
            var visibleDiv = null;
            citationSection.querySelectorAll('.bda-citation-text').forEach(function (div) {
                if (!div.hidden) visibleDiv = div;
            });

            if (!visibleDiv) return;

            // Prefer the plain-text version stored on the data attribute
            // (citation plain text has italic markers stripped; the rendered
            // HTML has <em> tags we don't want in the clipboard payload)
            var plain = visibleDiv.getAttribute('data-citation-plain');
            var text = plain || visibleDiv.textContent || '';
            copyToClipboard(text.trim(), statusEl);
        });
    }

    // ---------------------------------------------------------------------
    // Header permalink copy button
    // ---------------------------------------------------------------------

    function initHeaderPermalinkCopy() {
        var btn = document.querySelector('.bda-source-permalink-btn');
        if (!btn) return;

        var statusEl = document.getElementById('bda-source-permalink-status');

        btn.addEventListener('click', function () {
            copyToClipboard(window.location.href, statusEl);
        });
    }

    // ---------------------------------------------------------------------
    // Metadata rail permalink copy button
    // ---------------------------------------------------------------------

    function initRailPermalinkCopy() {
        // Event-delegated to handle the button that lives inside the dl
        var rail = document.querySelector('.bda-source-metadata-rail');
        if (!rail) return;

        rail.addEventListener('click', function (e) {
            var btn = e.target.closest && e.target.closest('.bda-source-permalink-copy');
            if (!btn) return;

            var statusEl = document.getElementById('bda-source-permalink-rail-status');
            // The button has data-permalink attribute with the exact URL;
            // fall back to window.location.href if the attribute is missing
            var permalink = btn.getAttribute('data-permalink') || window.location.href;
            copyToClipboard(permalink, statusEl);
        });
    }

    // ---------------------------------------------------------------------
    // Multi-asset viewer tab navigation (APG tablist pattern)
    // ---------------------------------------------------------------------

    function initMultiAssetTabs() {
        var viewer = document.querySelector('.bda-source-viewer-multi');
        if (!viewer) return;

        var tablist = viewer.querySelector('[role="tablist"]');
        if (!tablist) return;

        var tabs = Array.prototype.slice.call(tablist.querySelectorAll('[role="tab"]'));
        if (tabs.length === 0) return;

        function activate(idx, focus) {
            tabs.forEach(function (tab, i) {
                var isActive = (i === idx);
                tab.setAttribute('aria-selected', isActive ? 'true' : 'false');
                tab.setAttribute('tabindex', isActive ? '0' : '-1');

                var panelId = tab.getAttribute('aria-controls');
                var panel = panelId ? document.getElementById(panelId) : null;
                if (panel) panel.hidden = !isActive;
            });
            if (focus && tabs[idx]) tabs[idx].focus();
        }

        tabs.forEach(function (tab, i) {
            // Click activation
            tab.addEventListener('click', function () {
                activate(i, false);
            });

            // Keyboard navigation per WAI-ARIA tablist pattern
            tab.addEventListener('keydown', function (e) {
                switch (e.key) {
                    case 'ArrowRight':
                    case 'ArrowDown':
                        e.preventDefault();
                        activate((i + 1) % tabs.length, true);
                        break;
                    case 'ArrowLeft':
                    case 'ArrowUp':
                        e.preventDefault();
                        activate((i - 1 + tabs.length) % tabs.length, true);
                        break;
                    case 'Home':
                        e.preventDefault();
                        activate(0, true);
                        break;
                    case 'End':
                        e.preventDefault();
                        activate(tabs.length - 1, true);
                        break;
                }
            });
        });
    }

    // ---------------------------------------------------------------------
    // Init
    // ---------------------------------------------------------------------

    function init() {
        initCitationFormatToggle();
        initCitationCopyButton();
        initHeaderPermalinkCopy();
        initRailPermalinkCopy();
        initMultiAssetTabs();
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }
})();
